class Solution:
    def maximumSaleItems(self, items, budget):
        n = len(items)
        factors = [it[0] for it in items]
        prices = [it[1] for it in items]
        D = [sum(1 for j in range(n) if i != j and factors[j] % factors[i] == 0) for i in range(n)]
        NEG = float('-inf')
        dp = [NEG] * (budget + 1)
        dp[0] = 0
        for i in range(n):
            p = prices[i]
            d = D[i]
            if p > budget:
                continue
            ndp = dp[:]
            maxc = budget // p
            for c in range(1, maxc + 1):
                cost = c * p
                val = c + min(c, d)
                for b in range(cost, budget + 1):
                    if dp[b - cost] != NEG and dp[b - cost] + val > ndp[b]:
                        ndp[b] = dp[b - cost] + val
            dp = ndp
        return max(dp)

