class Solution:
    def maximumSaleItems(self, items, budget: int) -> int:
        n = len(items)
        factors = [it[0] for it in items]
        prices = [it[1] for it in items]
        maxF = max(factors)
        cnt = [0] * (maxF + 1)
        for f in factors:
            cnt[f] += 1
        divCount = [0] * (maxF + 1)
        for d in range(1, maxF + 1):
            s = 0
            for mult in range(d, maxF + 1, d):
                s += cnt[mult]
            divCount[d] = s
        D = [divCount[f] - 1 for f in factors]
        m = min(prices)
        buckets = {}
        for i in range(n):
            if D[i] > 0 and prices[i] <= 2 * m:
                buckets[prices[i]] = buckets.get(prices[i], 0) + D[i]
        total = 0
        b = budget
        for price in sorted(buckets):
            if b <= 0:
                break
            slots = buckets[price]
            take = min(slots, b // price)
            total += 2 * take
            b -= take * price
        total += b // m
        return total

