var maximumSaleItems = function(items, budget) {
    const n = items.length;
    const factors = items.map(it => it[0]);
    const prices = items.map(it => it[1]);
    const maxF = Math.max(...factors);
    const cnt = new Array(maxF + 1).fill(0);
    for (const f of factors) cnt[f]++;
    const divCount = new Array(maxF + 1).fill(0);
    for (let d = 1; d <= maxF; d++) {
        let s = 0;
        for (let mult = d; mult <= maxF; mult += d) s += cnt[mult];
        divCount[d] = s;
    }
    const D = factors.map(f => divCount[f] - 1);
    const m = Math.min(...prices);
    const buckets = new Map();
    for (let i = 0; i < n; i++) {
        if (D[i] > 0 && prices[i] <= 2 * m) {
            buckets.set(prices[i], (buckets.get(prices[i]) || 0) + D[i]);
        }
    }
    const sortedPrices = Array.from(buckets.keys()).sort((a, b) => a - b);
    let total = 0;
    let b = budget;
    for (const price of sortedPrices) {
        if (b <= 0) break;
        const slots = buckets.get(price);
        const take = Math.min(slots, Math.floor(b / price));
        total += 2 * take;
        b -= take * price;
    }
    total += Math.floor(b / m);
    return total;
};
